import hashlib
import sqlite3
from typing import Optional

def verify_user(username: str, password: str) -> Optional[dict]:
    """
    Verify user credentials against legacy database
    """
    try:
        # Connect to legacy database
        conn = sqlite3.connect('legacy_database.db')
        cursor = conn.cursor()
        
        # Secure query with parameter binding
        cursor.execute("""
            SELECT id, username, password_hash, salt 
            FROM users 
            WHERE username = ? AND active = 1
        """, (username,))
        
        user_record = cursor.fetchone()
        conn.close()
        
        if not user_record:
            return None
            
        user_id, db_username, stored_hash, salt = user_record
        
        # Secure password verification
        password_hash = hashlib.pbkdf2_hmac('sha256', 
                                           password.encode('utf-8'), 
                                           salt.encode('utf-8'), 
                                           100000).hex()
        
        if password_hash == stored_hash:
            return {
                'id': user_id,
                'username': db_username
            }
            
        return None
        
    except Exception:
        return None

def secure_login(username: str, password: str) -> bool:
    """
    Main login function with security checks
    """
    # Input validation
    if not username or not password:
        return False
        
    if len(username) > 50 or len(password) > 100:
        return False
        
    # Verify credentials
    user = verify_user(username, password)
    return user is not None